import {{ Injectable }} from '@nestjs/common';
import {{ UploadService }} from './models/upload.model';
import {{ UploadServiceRepository }} from './repositories/upload.repository';

@Injectable()
export class UploadServiceService {{
  constructor(
    private readonly repository: UploadServiceRepository,
  ) {{}}

  async findAll(): Promise<UploadService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<UploadService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<UploadService>): Promise<UploadService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<UploadService>): Promise<UploadService> {{
    return this.repository.update(id, data);
  }}
}}
